from llm_pipeline.ui.introspection import PipelineIntrospector

# Registry of discoverable pipelines (configured at startup)
_pipeline_registry: Dict[str, Type[PipelineConfig]] = {}

def register_pipeline(pipeline_class: Type[PipelineConfig]):
    name = pipeline_class.__name__
    _pipeline_registry[name] = pipeline_class

@router.get('/pipelines')
async def list_pipelines():
    # Return list of registered pipelines with summary metadata
    return {
        'pipelines': [
            {
                'name': name,
                'strategy_count': len(cls.STRATEGIES.STRATEGIES),
                'step_count': sum(len(s().get_steps()) for s in cls.STRATEGIES.STRATEGIES),
                'has_input_schema': hasattr(cls, 'INPUT_DATA'),
            }
            for name, cls in _pipeline_registry.items()
        ]
    }

@router.get('/pipelines/{pipeline_name}')
async def get_pipeline(pipeline_name: str):
    # Return full introspection data
    introspector = PipelineIntrospector(_pipeline_registry[pipeline_name])
    return introspector.get_metadata()
