import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'

export function useRuns(filters: RunFilters) {
  return useQuery({
    queryKey: ['runs', filters],
    queryFn: () => fetch(`/api/runs?${new URLSearchParams(filters)}`).then(r => r.json()),
    staleTime: 30_000,  // 30 seconds for active runs
  })
}

export function useRun(runId: string) {
  return useQuery({
    queryKey: ['runs', runId],
    queryFn: () => fetch(`/api/runs/${runId}`).then(r => r.json()),
  })
}

export function useCreateRun() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (data: CreateRunRequest) => 
      fetch('/api/runs', { method: 'POST', body: JSON.stringify(data) }),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['runs'] }),
  })
}
```

