import { DndContext, closestCenter } from '@dnd-kit/core'
import { SortableContext, verticalListSortingStrategy } from '@dnd-kit/sortable'

export function VisualEditor() {
  const [pipeline, setPipeline] = useState(null)
  const [steps, setSteps] = useState([])
  const [errors, setErrors] = useState([])

  const compileMutation = useCompilePipeline()

  const handleDragEnd = (event) => {
    // Reorder steps
    const { active, over } = event
    if (active.id !== over.id) {
      setSteps(reorder(steps, active.id, over.id))
    }
  }

  const handleCompile = async () => {
    const result = await compileMutation.mutateAsync({ structure: steps })
    if (!result.success) {
      setErrors(result.errors)
    }
  }

  return (
    <div className="flex h-full">
      {/* Center: Visual step sequence */}
      <div className="flex-1 p-4">
        <DndContext collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
          <SortableContext items={steps} strategy={verticalListSortingStrategy}>
            {steps.map(step => (
              <SortableStep 
                key={step.id} 
                step={step}
                error={errors.find(e => e.stepId === step.id)}
              />
            ))}
          </SortableContext>
        </DndContext>

        <button onClick={() => addStep()}>Add Step</button>
        <button onClick={handleCompile}>Compile</button>
      </div>

      {/* Right: Step properties panel */}
      <StepPropertiesPanel />
    </div>
  )
}
